targets.expr:
100 * max by (pod) (
  container_memory_working_set_bytes{namespace=~"$namespace", container!="", pod!=""}
  /
  on(container, pod)
  label_replace(
    kube_pod_container_resource_limits{namespace=~"$namespace", resource="memory", unit="byte"},
    "pod", "$1", "exported_pod", "(.+)"
  )
)
